class Solution {
public:
    int minMovesToMakePalindrome(string s) {
        int n = s.size();
        vector<int> pos(26, -1);
        for (int i = 0; i < n; i++) {
            if (pos[s[i] - 'a'] == -1) {
                pos[s[i] - 'a'] = i;
            } else {
                pos[s[i] - 'a'] = i;
            }
        }

        int moves = 0;
        int left = 0, right = n - 1;
        while (left < right) {
            if (s[left] == s[right]) {
                left++;
                right--;
            } else {
                int idx = pos[s[right] - 'a'];
                if (idx < right) {
                    moves += right - idx - (right - left - 1);
                    pos[s[right] - 'a'] = right;
                    right--;
                } else {
                    moves += idx - left - (right - left - 1);
                    pos[s[left] - 'a'] = left;
                    left++;
                }
            }
        }
        return moves;
    }
};
